sql:
SELECT cemetery_name, location, type, establishment_date, contact_info, website, description
FROM cemeteries
WHERE country = 'United States';

SELECT cemetery_name 
FROM cemeteries 
ORDER BY establishment_date ASC;

SELECT c.country, c.cemetery_name, c.contact_info
FROM cemeteries c
INNER JOIN countries co ON c.country = co.country_name;

SELECT c.country_name
FROM countries c
WHERE c.population > (SELECT AVG(population) FROM countries);

SELECT cemetery_name, location
FROM cemeteries
WHERE country = 'Iraq';

SELECT AVG(c.population) AS average_population
FROM countries c
INNER JOIN cemeteries ce ON c.country_name = ce.country;

SELECT casualty_id, rank_id 
FROM casualty_ranks
WHERE casualty_id = 1;
